const express = require('express');
const { graphqlHTTP } = require('express-graphql');
const { buildSchema } = require('graphql');
const { Pool } = require('pg');

// Initialize PostgreSQL client
const pool = new Pool({
  user: 'your_user',
  host: 'localhost',
  database: 'your_database',
  password: 'your_password',
  port: 5432,
});

// GraphQL schema
const schema = buildSchema(`
  type Author {
    id: ID!
    name: String!
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    author: Author
  }

  type Query {
    posts: [Post]
  }
`);

// Resolvers
const root = {
  posts: async () => {
    const res = await pool.query('SELECT * FROM posts');
    return res.rows;
  },
  author: async (post) => {
    const res = await pool.query('SELECT * FROM authors WHERE id = $1', [post.author_id]);
    return res.rows[0];
  },
};

// Express server setup
const app = express();
app.use('/graphql', graphqlHTTP({
  schema: schema,
  rootValue: root,
  graphiql: true,
}));

app.listen(4000, () => {
  console.log('Server is running on http://localhost:4000/graphql');
});

